  1→import { useBackgroundProcessing } from "@/features/background-processing/context/BackgroundProcessingContext";
  2→import { useRecipes } from "@/features/recipes-list/context/RecipesContext";
  3→import { useSources } from "@/features/sources/context/SourcesContext";
  4→import { Alert } from "@/lib/alert";
  5→import { LANGUAGE_DISPLAY_NAMES } from "@/lib/types/language";
  6→import { APP_LANGUAGES } from "@/lib/types/language";
  7→import type { SourceId } from "@/lib/types/primitives";
  8→import type { Source } from "@/lib/types/source";
  9→import { isUrl } from "@/lib/utils/recipeValidation";
 10→import { LiquidGlassButton, LiquidGlassInput } from "@/modules/liquid-glass";
 11→import { useTranslation } from "@/platform/i18n/useTranslation";
 12→import { getColors } from "@/platform/theme/glassStyles";
 13→import { useTheme } from "@/platform/theme/useTheme";
 14→import { MaterialIcons } from "@expo/vector-icons";
 15→import * as Haptics from "expo-haptics";
 16→import { router } from "expo-router";
 17→import { useCallback, useEffect, useMemo, useRef, useState, type JSX } from "react";
 18→import {
 19→  KeyboardAvoidingView,
 20→  LayoutAnimation,
 21→  Platform,
 22→  Pressable,
 23→  ScrollView,
 24→  StyleSheet,
 25→  Text,
 26→  TextInput,
 27→  View,
 28→} from "react-native";
 29→import { Gesture, GestureDetector } from "react-native-gesture-handler";
 30→import Animated, {
 31→  type SharedValue,
 32→  interpolate,
 33→  interpolateColor,
 34→  runOnJS,
 35→  useAnimatedStyle,
 36→  useSharedValue,
 37→  withSpring,
 38→} from "react-native-reanimated";
 39→import { useSafeAreaInsets } from "react-native-safe-area-context";
 40→
 41→function useActionButtonScale(
 42→  translateX: SharedValue<number>,
 43→  sign: 1 | -1,
 44→  offset = 0
 45→): { transform: Array<{ scale: number }>; opacity: number } {
 46→  return useAnimatedStyle(() => {
 47→    const w = Math.max(sign * translateX.value - offset - BUTTON_GAP, 0);
 48→    if (w <= SCALE_MIN_WIDTH) {
 49→      return { transform: [{ scale: 0 }], opacity: 0 };
 50→    }
 51→    if (w < BUTTON_SCALE_THRESHOLD) {
 52→      const s =
 53→        (w - SCALE_MIN_WIDTH) / (BUTTON_SCALE_THRESHOLD - SCALE_MIN_WIDTH);
 54→      return { transform: [{ scale: s }], opacity: s };
 55→    }
 56→    return { transform: [{ scale: 1 }], opacity: 1 };
 57→  });
 58→}
 59→
 60→const SWIPE_THRESHOLD = 60;
 61→const ACTION_BUTTON_WIDTH = 80;
 62→const LEFT_REVEAL_WIDTH = ACTION_BUTTON_WIDTH * 2;
 63→const BUTTON_GAP = 12;
 64→const BUTTON_CONTENT_WIDTH = ACTION_BUTTON_WIDTH - BUTTON_GAP;
 65→const BUTTON_SCALE_THRESHOLD = BUTTON_CONTENT_WIDTH;
 66→const SCALE_MIN_WIDTH = 10;
 67→
 68→function SwipeableBookRow({
 69→  source,
 70→  recipeCount,
 71→  editingSourceId,
 72→  onDelete,
 73→  onStartEdit,
 74→  onSetLanguage,
 75→  onConfirmEdit,
 76→  onCancelEdit,
 77→  editText,
 78→  onEditTextChange,
 79→}: {
 80→  source: Source;
 81→  recipeCount: number;
 82→  editingSourceId: SourceId | null;
 83→  onDelete: (sourceId: SourceId) => void;
 84→  onStartEdit: (sourceId: SourceId) => void;
 85→  onSetLanguage: (sourceId: SourceId, onDone: () => void) => void;
 86→  onConfirmEdit: () => void;
 87→  onCancelEdit: () => void;
 88→  editText: string;
 89→  onEditTextChange: (text: string) => void;
 90→}): JSX.Element {
 91→  const { t } = useTranslation();
 92→  const theme = useTheme();
 93→  const colors = getColors(theme);
 94→  const isDark = theme === "dark";
 95→  const textColor = isDark ? "#FFFFFF" : "#000000";
 96→  const translateX = useSharedValue(0);
 97→  const startX = useSharedValue(0);
 98→  const isEditing = editingSourceId === source.id;
 99→  const isEditingShared = useSharedValue(isEditing);
100→
101→  isEditingShared.value = isEditing;
102→
103→  useEffect(() => {
104→    translateX.value = withSpring(isEditing ? LEFT_REVEAL_WIDTH : 0);
105→  }, [isEditing, translateX]);
106→
107→  const triggerDelete = useCallback(() => {
108→    translateX.value = withSpring(0);
109→    onDelete(source.id);
110→  }, [source.id, onDelete, translateX]);
111→
112→  const handleLanguagePress = useCallback(() => {
113→    onSetLanguage(source.id, () => {
114→      translateX.value = withSpring(0);
115→    });
116→  }, [source.id, onSetLanguage, translateX]);
117→
118→  const handleEditPress = useCallback(() => {
119→    if (isEditing) {
120→      onConfirmEdit();
121→    } else {
122→      onStartEdit(source.id);
123→    }
124→  }, [isEditing, onConfirmEdit, onStartEdit, source.id]);
125→
126→  const pan = Gesture.Pan()
127→    .activeOffsetX([-10, 10])
128→    .failOffsetY([-10, 10])
129→    .onStart(() => {
130→      startX.value = translateX.value;
131→    })
132→    .onUpdate((event) => {
133→      const raw = startX.value + event.translationX;
134→      const leftLimit = LEFT_REVEAL_WIDTH * 1.5;
135→      const rightLimit = ACTION_BUTTON_WIDTH * 1.5;
136→      translateX.value = Math.max(-rightLimit, Math.min(leftLimit, raw));
137→    })
138→    .onEnd(() => {
139→      if (isEditingShared.value) {
140→        if (translateX.value < SWIPE_THRESHOLD / 2) {
141→          translateX.value = withSpring(0);
142→          runOnJS(onCancelEdit)();
143→        } else {
144→          translateX.value = withSpring(LEFT_REVEAL_WIDTH);
145→        }
146→      } else {
147→        if (translateX.value < -SWIPE_THRESHOLD) {
148→          translateX.value = withSpring(-ACTION_BUTTON_WIDTH);
149→        } else if (translateX.value > SWIPE_THRESHOLD) {
150→          translateX.value = withSpring(LEFT_REVEAL_WIDTH);
151→        } else {
152→          translateX.value = withSpring(0);
153→        }
154→      }
155→    });
156→
157→  const tap = Gesture.Tap().onEnd(() => {
158→    if (Math.abs(translateX.value) > 10 && !isEditingShared.value) {
159→      translateX.value = withSpring(0);
160→    }
161→  });
162→
163→  const gesture = Gesture.Race(pan, tap);
164→
165→  const contentAnimStyle = useAnimatedStyle(() => ({
166→    transform: [{ translateX: translateX.value }],
167→  }));
168→
169→  const contentBgStyle = useAnimatedStyle(() => {
170→    const absX = Math.abs(translateX.value);
171→    const progress = Math.min(absX / SWIPE_THRESHOLD, 1);
172→    const bgColor = interpolateColor(
173→      progress,
174→      [0, 1],
175→      isDark
176→        ? ["rgba(44,43,45,0)", "#2c2b2d"]
177→        : ["rgba(128,128,128,0)", "rgba(128,128,128,0.12)"]
178→    );
179→    return {
180→      backgroundColor: bgColor,
181→      borderRadius: interpolate(progress, [0, 1], [0, 21]),
182→    };
183→  });
184→
185→  const langButtonWidthStyle = useAnimatedStyle(() => ({
186→    width: translateX.value > BUTTON_GAP ? Math.min(translateX.value - BUTTON_GAP, BUTTON_CONTENT_WIDTH) : 0,
187→    opacity: translateX.value > BUTTON_GAP ? 1 : 0,
188→  }));
189→
190→  const editButtonWidthStyle = useAnimatedStyle(() => {
191→    const available = translateX.value - ACTION_BUTTON_WIDTH;
192→    return {
193→      width: available > BUTTON_GAP ? available - BUTTON_GAP : 0,
194→      opacity: available > BUTTON_GAP ? 1 : 0,
195→    };
196→  });
197→
198→  const deleteButtonWidthStyle = useAnimatedStyle(() => ({
199→    width: -translateX.value > BUTTON_GAP ? -translateX.value - BUTTON_GAP : 0,
200→    opacity: -translateX.value > BUTTON_GAP ? 1 : 0,
201→  }));
202→
203→  const langScaleStyle = useActionButtonScale(translateX, 1);
204→  const editScaleStyle = useActionButtonScale(translateX, 1, ACTION_BUTTON_WIDTH);
205→  const deleteScaleStyle = useActionButtonScale(translateX, -1);
206→
207→  return (
208→    <View style={styles.rowContainer}>
209→      {/* Language button - left-most */}
210→      <Animated.View
211→        style={[
212→          styles.actionButtonContainer,
213→          styles.langButtonContainer,
214→          langButtonWidthStyle,
215→        ]}
216→      >
217→        <Pressable
218→          onPress={handleLanguagePress}
219→          style={styles.actionButtonPressable}
220→          accessibilityRole="button"
221→          accessibilityLabel={t("manageBooks.setLanguageAction")}
222→        >
223→          <Animated.View style={[styles.actionButtonContent, langScaleStyle]}>
224→            <View style={[styles.actionButtonIcon, styles.langButtonColor]}>
225→              <MaterialIcons name="language" size={26} color="#FFFFFF" />
226→            </View>
227→            <Text numberOfLines={1} style={[styles.actionButtonLabel, { color: colors.textSecondary }]}>
228→              {t("manageBooks.setLanguageAction")}
229→            </Text>
230→          </Animated.View>
231→        </Pressable>
232→      </Animated.View>
233→
234→      {/* Edit button - left, next to language */}
235→      <Animated.View
236→        style={[
237→          styles.actionButtonContainer,
238→          styles.editButtonContainer,
239→          editButtonWidthStyle,
240→        ]}
241→      >
242→        <Pressable
243→          onPress={handleEditPress}
244→          style={styles.actionButtonPressable}
245→          accessibilityRole="button"
246→          accessibilityLabel={
247→            isEditing
248→              ? t("manageBooks.confirmEditAction")
249→              : t("manageBooks.editAction")
250→          }
251→        >
252→          <Animated.View style={[styles.actionButtonContent, editScaleStyle]}>
253→            <View style={[styles.actionButtonIcon, styles.editButtonColor]}>
254→              <MaterialIcons
255→                name={isEditing ? "check" : "edit"}
256→                size={26}
257→                color="#FFFFFF"
258→              />
259→            </View>
260→            <Text numberOfLines={1} style={[styles.actionButtonLabel, { color: colors.textSecondary }]}>
261→              {isEditing
262→                ? t("manageBooks.confirmEditAction")
263→                : t("manageBooks.editAction")}
264→            </Text>
265→          </Animated.View>
266→        </Pressable>
267→      </Animated.View>
268→
269→      {/* Delete button - right */}
270→      <Animated.View
271→        style={[
272→          styles.actionButtonContainer,
273→          styles.deleteButtonContainer,
274→          deleteButtonWidthStyle,
275→        ]}
276→      >
277→        <Pressable
278→          onPress={triggerDelete}
279→          style={styles.actionButtonPressable}
280→          accessibilityRole="button"
281→          accessibilityLabel={t("manageBooks.deleteConfirmAction")}
282→        >
283→          <Animated.View style={[styles.actionButtonContent, deleteScaleStyle]}>
284→            <View style={[styles.actionButtonIcon, styles.deleteButtonColor]}>
285→              <MaterialIcons name="delete" size={26} color="#FFFFFF" />
286→            </View>
287→            <Text numberOfLines={1} style={[styles.actionButtonLabel, { color: colors.textSecondary }]}>
288→              {t("manageBooks.deleteConfirmAction")}
289→            </Text>
290→          </Animated.View>
291→        </Pressable>
292→      </Animated.View>
293→
294→      {/* Content */}
295→      <GestureDetector gesture={gesture}>
296→        <Animated.View style={[styles.listItem, contentAnimStyle, contentBgStyle]}>
297→          {isEditing ? (
298→            <>
299→              <TextInput
300→                style={[styles.editInput, { color: textColor }]}
301→                value={editText}
302→                onChangeText={onEditTextChange}
303→                maxLength={100}
304→                multiline
305→                autoFocus
306→                selectTextOnFocus
307→                blurOnSubmit
308→                returnKeyType="done"
309→                onSubmitEditing={onConfirmEdit}
310→              />
311→              <Text
312→                style={[styles.recipeCount, { color: colors.textSecondary }]}
313→              >
314→                {t("manageBooks.recipeCount", { count: recipeCount })}
315→                {" · "}
316→                {source.language.toUpperCase()}
317→              </Text>
318→            </>
319→          ) : (
320→            <>
321→              <Text style={[styles.bookTitle, { color: textColor }]}>
322→                {source.name}
323→              </Text>
324→              <Text
325→                style={[styles.recipeCount, { color: colors.textSecondary }]}
326→              >
327→                {t("manageBooks.recipeCount", { count: recipeCount })}
328→                {" · "}
329→                {source.language.toUpperCase()}
330→              </Text>
331→            </>
332→          )}
333→        </Animated.View>
334→      </GestureDetector>
335→
336→    </View>
337→  );
338→}
