  return Math.max(
    MIN_SUGGESTIONS_WIDTH,
    Math.min(MAX_SUGGESTIONS_WIDTH, estimatedWidth)
  );
}, [liquidSuggestions]);

const suggestionsPanelHeight = liquidSuggestions.length * SUGGESTION_ROW_HEIGHT;

